import React from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../../types';

export type CwmPermissionEditProps = IconProps;

const CwmPermissionEditLight: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <rect x="2" y="12" width="8" height="1" rx=".5" fill="#E66D17" />
    <rect x="2" y="6" width="8" height="1" rx=".5" fill="#E66D17" />
    <rect x="2" y="9" width="12" height="1" rx=".5" fill="#E66D17" />
    <rect x="2" y="3" width="12" height="1" rx=".5" fill="#E66D17" />
  </svg>
);

const CwmPermissionEditDark: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <rect x="2" y="12" width="8" height="1" rx=".5" fill="#F2C55C" />
    <rect x="2" y="6" width="8" height="1" rx=".5" fill="#F2C55C" />
    <rect x="2" y="9" width="12" height="1" rx=".5" fill="#F2C55C" />
    <rect x="2" y="3" width="12" height="1" rx=".5" fill="#F2C55C" />
  </svg>
);

export const CwmPermissionEdit: React.FC<CwmPermissionEditProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light' ? CwmPermissionEditLight : CwmPermissionEditDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
